import { Entity, PrimaryGeneratedColumn, Column, CreateDateColumn, ManyToOne, JoinColumn } from 'typeorm';
import { Usuario } from '../../usuarios/entities/usuario.entity';

@Entity('avaliacoes')
export class Avaliacao {
  @PrimaryGeneratedColumn('uuid')
  id: string;

  @Column({ type: 'int' })
  nota: number;

  @CreateDateColumn({ type: 'timestamptz' })
  criadoEm: Date;

  @ManyToOne(() => Usuario, { nullable: true })
  @JoinColumn({ name: 'usuario_id' })
  usuario?: Usuario | null;
}

import { IsInt, Min, Max, IsOptional } from 'class-validator';

export class CreateAvaliacaoDto {
  @IsInt()
  @Min(0)
  @Max(5)
  nota: number;

  @IsOptional()
  usuarioId?: string;
}

import { Injectable, Logger, BadRequestException } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { Avaliacao } from './entities/avaliacao.entity';
import { CreateAvaliacaoDto } from './dto/create-avaliacao.dto';

@Injectable()
export class AvaliacoesService {
  private readonly logger = new Logger(AvaliacoesService.name);

  constructor(
    @InjectRepository(Avaliacao)
    private readonly avaliacaoRepo: Repository<Avaliacao>,
  ) {}

  /**
   * Cria e salva uma avaliação após validar nota
   * @param dto Dados da avaliação
   * @returns Avaliação salva
   */
  async criarAvaliacao(dto: CreateAvaliacaoDto): Promise<Avaliacao> {
    if (dto.nota < 0 || dto.nota > 5) {
      this.logger.warn({ message: 'Nota inválida recebida', nota: dto.nota });
      throw new BadRequestException('Nota deve estar entre 0 e 5');
    }

    const avaliacao = this.avaliacaoRepo.create({
      nota: dto.nota,
    });

    if (dto.usuarioId) {
      avaliacao.usuario = { id: dto.usuarioId } as any;
    }

    await this.avaliacaoRepo.save(avaliacao);

    this.logger.log({ message: 'Avaliação criada com sucesso', avaliacaoId: avaliacao.id, nota: avaliacao.nota });
    return avaliacao;
  }
}

import { Controller, Post, Body, UseGuards, Req, BadRequestException } from '@nestjs/common';
import { AvaliacoesService } from './avaliacoes.service';
import { CreateAvaliacaoDto } from './dto/create-avaliacao.dto';
import { JwtAuthGuard } from '../auth/guards/jwt-auth.guard';
import { Request } from 'express';

@Controller('avaliacoes')
export class AvaliacoesController {
  constructor(private readonly avaliacoesService: AvaliacoesService) {}

  @UseGuards(JwtAuthGuard)
  @Post()
  async submitAvaliacao(@Body() dto: CreateAvaliacaoDto, @Req() req: Request) {
    // Associar usuário autenticado se presente
    if (!dto.usuarioId && req.user && typeof req.user === 'object' && 'id' in req.user) {
      dto.usuarioId = (req.user as any).id;
    }

    try {
      const avaliacao = await this.avaliacoesService.criarAvaliacao(dto);
      return { success: true, message: 'Avaliação registrada com sucesso', id: avaliacao.id };
    } catch (error) {
      if (error instanceof BadRequestException) {
        throw new BadRequestException(error.message);
      }
      throw error;
    }
  }
}

import { Module } from '@nestjs/common';
import { TypeOrmModule } from '@nestjs/typeorm';
import { Avaliacao } from './entities/avaliacao.entity';
import { AvaliacoesService } from './avaliacoes.service';
import { AvaliacoesController } from './avaliacoes.controller';

@Module({
  imports: [TypeOrmModule.forFeature([Avaliacao])],
  providers: [AvaliacoesService],
  controllers: [AvaliacoesController],
  exports: [AvaliacoesService],
})
export class AvaliacoesModule {}

import React, { useState, useEffect, useCallback } from 'react';
import axios from 'axios';

interface AvaliacaoResponse {
  success: boolean;
  message: string;
  id?: string;
}

const FrasesPage: React.FC = () => {
  const [frases, setFrases] = useState<string[]>([]);
  const [nota, setNota] = useState<number | null>(null);
  const [avaliacaoEnviada, setAvaliacaoEnviada] = useState(false);
  const [loading, setLoading] = useState(false);
  const [mensagem, setMensagem] = useState<string | null>(null);

  // Simulação de geração de frases
  useEffect(() => {
    // Simular frases geradas após 1s
    setTimeout(() => {
      setFrases([
        'Frase gerada 1',
        'Frase gerada 2',
        'Frase gerada 3'
      ]);
    }, 1000);
  }, []);

  const handleNotaChange = useCallback((event: React.ChangeEvent<HTMLSelectElement>) => {
    const valor = parseInt(event.target.value, 10);
    if (!isNaN(valor) && valor >= 0 && valor <= 5) {
      setNota(valor);
    }
  }, []);

  const submitAvaliacao = useCallback(async () => {
    if (nota === null) {
      setMensagem('Por favor, selecione uma nota antes de enviar.');
      return;
    }
    setLoading(true);
    setMensagem(null);

    try {
      const response = await axios.post<AvaliacaoResponse>('/api/avaliacoes', { nota });
      if (response.data.success) {
        setMensagem('Avaliação registrada com sucesso. Obrigado pelo seu feedback!');
        setAvaliacaoEnviada(true);
      } else {
        setMensagem('Erro ao registrar avaliação: ' + response.data.message);
      }
    } catch (error: any) {
      setMensagem('Falha ao enviar avaliação. Por favor, tente novamente.');
    } finally {
      setLoading(false);
    }
  }, [nota]);

  return (
    <main>
      <h1>Frases Geradas</h1>
      {frases.length === 0 ? (
        <p>Gerando frases...</p>
      ) : (
        <>
          <ul aria-live="polite">
            {frases.map((frase, idx) => (
              <li key={idx}>{frase}</li>
            ))}
          </ul>

          {!avaliacaoEnviada && (
            <section aria-label="Avaliação das frases">
              <label htmlFor="nota-avaliacao">Avalie as frases (0 a 5):</label>
              <select
                id="nota-avaliacao"
                value={nota !== null ? nota : ''}
                onChange={handleNotaChange}
                disabled={loading}
                aria-required="true"
              >
                <option value="" disabled>
                  Selecione
                </option>
                {[0, 1, 2, 3, 4, 5].map((num) => (
                  <option key={num} value={num}>
                    {num}
                  </option>
                ))}
              </select>
              <button onClick={submitAvaliacao} disabled={loading || nota === null} aria-disabled={loading || nota === null}>
                {loading ? 'Enviando...' : 'Enviar Avaliação'}
              </button>
            </section>
          )}

          {mensagem && <p role="alert">{mensagem}</p>}
        </>
      )}
    </main>
  );
};

export default FrasesPage;

