import { Test, TestingModule } from '@nestjs/testing';
import { AvaliacoesService } from './avaliacoes.service';
import { getRepositoryToken } from '@nestjs/typeorm';
import { Avaliacao } from './entities/avaliacao.entity';
import { Repository } from 'typeorm';
import { BadRequestException } from '@nestjs/common';

describe('AvaliacoesService', () => {
  let service: AvaliacoesService;
  let repository: jest.Mocked<Repository<Avaliacao>>;

  beforeEach(async () => {
    const module: TestingModule = await Test.createTestingModule({
      providers: [
        AvaliacoesService,
        {
          provide: getRepositoryToken(Avaliacao),
          useValue: {
            create: jest.fn(),
            save: jest.fn(),
          },
        },
      ],
    }).compile();

    service = module.get<AvaliacoesService>(AvaliacoesService);
    repository = module.get(getRepositoryToken(Avaliacao));
  });

  it('deve criar avaliação válida e salvar', async () => {
    const dto = { nota: 4 };
    const avaliacaoMock = { id: 'abc123', nota: 4, criadoEm: new Date() } as Avaliacao;
    repository.create.mockReturnValue(avaliacaoMock);
    repository.save.mockResolvedValue(avaliacaoMock);

    const result = await service.criarAvaliacao(dto);

    expect(repository.create).toHaveBeenCalledWith({ nota: dto.nota });
    expect(repository.save).toHaveBeenCalledWith(avaliacaoMock);
    expect(result).toEqual(avaliacaoMock);
  });

  it('deve rejeitar nota menor que 0', async () => {
    await expect(service.criarAvaliacao({ nota: -1 })).rejects.toThrow(BadRequestException);
  });

  it('deve rejeitar nota maior que 5', async () => {
    await expect(service.criarAvaliacao({ nota: 6 })).rejects.toThrow(BadRequestException);
  });

  it('deve associar usuario se usuarioId fornecido', async () => {
    const dto = { nota: 3, usuarioId: 'user-1' };
    const avaliacaoMock = { id: 'abc123', nota: 3, criadoEm: new Date(), usuario: { id: 'user-1' } } as Avaliacao;
    repository.create.mockReturnValue(avaliacaoMock);
    repository.save.mockResolvedValue(avaliacaoMock);

    const result = await service.criarAvaliacao(dto);

    expect(result.usuario).toBeDefined();
    expect(result.usuario.id).toBe('user-1');
  });
});
